pub(crate) fn max_turns_default() -> usize {
    std::env::var("MOONSHINE_AGENT_MAX_TURNS")
        .ok()
        .and_then(|v| v.trim().parse::<usize>().ok())
        .filter(|v| *v > 0)
        .unwrap_or(6)
}

pub(crate) fn max_tool_calls_default() -> usize {
    std::env::var("MOONSHINE_AGENT_MAX_TOOL_CALLS")
        .ok()
        .and_then(|v| v.trim().parse::<usize>().ok())
        .filter(|v| *v > 0)
        .unwrap_or(4)
}

fn result_chars_default(brain_kind: BrainKind) -> usize {
    std::env::var("MOONSHINE_AGENT_TOOL_RESULT_CHARS")
        .ok()
        .and_then(|v| v.trim().parse::<usize>().ok())
        .filter(|v| *v > 0)
        .unwrap_or(match brain_kind {
            // The fat-station feeds prompt tokens one HTTP call at a time —
            // every feedback character is real wall-clock.
            BrainKind::FatStation => 600,
            _ => 2000,
        })
}

/// Prompt-size caps by brain: the fat-station 0.5B gets a tighter contract.
pub(crate) struct PromptCaps {
    pub(crate) max_candidates: usize,
    pub(crate) desc_chars: usize,
    pub(crate) result_chars: usize,
}

pub(crate) fn prompt_caps(brain_kind: BrainKind) -> PromptCaps {
    match brain_kind {
        BrainKind::FatStation => PromptCaps {
            max_candidates: 3,
            desc_chars: 120,
            result_chars: result_chars_default(brain_kind),
        },
        _ => PromptCaps {
            max_candidates: usize::MAX,
            desc_chars: 200,
            result_chars: result_chars_default(brain_kind),
        },
    }
}

pub(crate) struct AgentLoopConfig {
    pub(crate) run_id: String,
    pub(crate) permission_mode: AgentPermissionMode,
    pub(crate) provider: String,
    pub(crate) max_turns: usize,
    pub(crate) max_tool_calls: usize,
    /// Aeon-12 tool-economy budget (`R` fed to `god_weight`). Narrows what
    /// gets offered as it drains; never itself ends the loop — that stays
    /// `max_turns`/`max_tool_calls`'s job.
    pub(crate) max_stamina: u32,
    /// true: NDJSON events go to stdout + ledger (exec --json).
    /// false: events go to the ledger only; stdout stays human (REPL).
    pub(crate) json_events: bool,
    pub(crate) ledger_path: Option<PathBuf>,
    pub(crate) workspace: PathBuf,
    /// Interactive sessions resolve `escalate` with an inline y/N prompt;
    /// non-interactive runs park a pending intent for `agentic approve-tool`.
    pub(crate) interactive: bool,
}

#[derive(Debug)]
pub(crate) enum LoopOutcome {
    Answer(String),
    BudgetExhausted(String),
    NeedsApproval { intent_id: String },
}

impl LoopOutcome {
    pub(crate) fn text(&self) -> Option<&str> {
        match self {
            LoopOutcome::Answer(text) | LoopOutcome::BudgetExhausted(text) => Some(text),
            LoopOutcome::NeedsApproval { .. } => None,
        }
    }
}

// ---------------------------------------------------------------------------
// Prompt contract
// ---------------------------------------------------------------------------

/// OpenAI-style `tools` array built from the same candidate data
/// `build_system_prompt` walks — used only when `native_tools_enabled()` and
/// the brain is talking to an endpoint that implements the agentic
/// `tools`/`tool_calls` contract (see `brain::openai_chat_complete_with_tools`).
pub(crate) fn build_native_tools_json(candidates: &[&AgentIndexedTool]) -> serde_json::Value {
    serde_json::Value::Array(
        candidates
            .iter()
            .map(|tool| {
                serde_json::json!({
                    "type": "function",
                    "function": {
                        "name": tool.name,
                        "description": tool.description,
                        "parameters": tool.meta.input_schema,
                    },
                })
            })
            .collect(),
    )
}

pub(crate) fn build_system_prompt(candidates: &[&AgentIndexedTool], caps: &PromptCaps) -> String {
    let mut prompt = String::from(
        "You are Moonshine, a terminal agent. You may call ONE tool per turn to help answer.\n\n\
To call a tool, output EXACTLY this format and nothing else:\n\n\
```tool_call\n\
{\"name\": \"TOOL_NAME\", \"arguments\": {\"param\": \"value\"}}\n\
```\n\n\
Example:\n\n\
```tool_call\n\
{\"name\": \"network/search\", \"arguments\": {\"query\": \"weather tools\"}}\n\
```\n\n\
Rules:\n\
1. Only use a tool named under AVAILABLE TOOLS. Never invent tool names.\n\
2. \"arguments\" must be a JSON object containing every required parameter.\n\
3. If no tool is needed, answer the user directly in plain text and do not mention tools.\n\
4. After a line starting with TOOL RESULT, use the result: either call another tool or give the final answer in plain text.\n\n\
AVAILABLE TOOLS:\n",
    );
    for tool in candidates {
        prompt.push_str("\n### ");
        prompt.push_str(&tool.name);
        prompt.push('\n');
        if !tool.description.is_empty() {
            prompt.push_str(&truncate_chars(&tool.description, caps.desc_chars));
            prompt.push('\n');
        }
        let schema = &tool.meta.input_schema;
        let required: HashSet<&str> = schema
            .get("required")
            .and_then(|v| v.as_array())
            .map(|items| items.iter().filter_map(|v| v.as_str()).collect())
            .unwrap_or_default();
        if let Some(props) = schema.get("properties").and_then(|v| v.as_object()) {
            if !props.is_empty() {
                prompt.push_str("Parameters:\n");
                for (key, spec) in props {
                    let detail = spec
                        .get("description")
                        .and_then(|v| v.as_str())
                        .map(|d| truncate_chars(d, caps.desc_chars))
                        .or_else(|| {
                            spec.get("type")
                                .and_then(|v| v.as_str())
                                .map(ToString::to_string)
                        })
                        .unwrap_or_default();
                    prompt.push_str("  - ");
                    prompt.push_str(key);
                    if !detail.is_empty() {
                        prompt.push_str(": ");
                        prompt.push_str(&detail);
                    }
                    if required.contains(key.as_str()) {
                        prompt.push_str(" (required)");
                    }
                    prompt.push('\n');
                }
            }
        }
    }
    prompt
}

/// Aeon-12 "winded" narrowing: once the tool economy's power gauge floors,
/// only read-only tools stay on offer for the rest of the turn — a model
/// with an empty dial cannot even attempt a mutation. Not narrowed at all
/// when the economy isn't winded.
pub(crate) fn narrow_if_winded<'a>(
    candidates: &[&'a AgentIndexedTool],
    candidate_risk: &HashMap<String, &'static str>,
    winded: bool,
) -> Vec<&'a AgentIndexedTool> {
    if !winded {
        return candidates.to_vec();
    }
    candidates
        .iter()
        .copied()
        .filter(|t| candidate_risk.get(&t.name).copied() == Some("read_only"))
        .collect()
}

/// Bar for "a strong local cue was genuinely on offer" — well above the
/// `>= 6` "worth listing as a candidate at all" bar used by
/// `merge_candidate_tools`. Calibrated against a real multi-tool catalog (not
/// a single-tool fixture, where document-frequency rarity weighting would
/// degenerately read every token as maximally rare) — a genuine strong match
/// (name substring + description substring + meta-domain hit, all against a
/// realistically populated, mostly-unrelated catalog) clears this; a lone
/// weak hit does not.
const STRONG_LOCAL_CUE_THRESHOLD: usize = 20;

/// `full_catalog` (the whole tool index, not the narrowed `candidates` this
/// turn is offering) feeds document-frequency rarity weighting — a token's
/// rarity is a property of the whole tool universe, not of whatever subset
/// survived this turn's economy/candidate narrowing.
fn has_strong_local_cue(
    input: &str,
    full_catalog: &[AgentIndexedTool],
    candidates: &[&AgentIndexedTool],
) -> bool {
    let tokens = super::prompt_cue_tokens(input);
    if tokens.is_empty() {
        return false;
    }
    let token_df = super::compute_token_df(full_catalog, &tokens);
    let total_tools = full_catalog.len();
    candidates.iter().any(|tool| {
        super::score_indexed_tool(tool, &tokens, &token_df, total_tools) >= STRONG_LOCAL_CUE_THRESHOLD
    })
}

/// Pure trigger for the skymesh plain-prose retry — no I/O, unit-testable
/// without an HTTP mock. Fires only once: turn 1, only for the `skymesh`
/// backend (`BrainKind::Auto`'s first try), only when the model answered in
/// prose despite the tool contract, and only when a strong local tool match
/// was genuinely on offer — never forces a tool call into existence when the
/// candidates were weak to begin with.
fn should_retry_via_fat_station(
    turn: usize,
    backend: &str,
    is_plain_prose: bool,
    has_strong_cue: bool,
) -> bool {
    turn == 1 && backend == "skymesh" && is_plain_prose && has_strong_cue
}

fn truncate_chars(text: &str, max_chars: usize) -> String {
    if text.chars().count() <= max_chars {
        return text.to_string();
    }
    let mut out: String = text.chars().take(max_chars).collect();
    out.push_str("… (truncated)");
    out
}

/// Flatten an MCP tool result for feedback: prefer the superserver's
/// `content[0].text`, fall back to compact JSON, truncate hard.
pub(crate) fn tool_result_text(result: &serde_json::Value, max_chars: usize) -> String {
    let text = result
        .get("content")
        .and_then(|value| value.as_array())
        .and_then(|items| items.first())
        .and_then(|item| item.get("text"))
        .and_then(|value| value.as_str())
        .map(ToString::to_string)
        .unwrap_or_else(|| result.to_string());
    truncate_chars(&text, max_chars)
}

// ---------------------------------------------------------------------------
// Forgiving tool-call parser
// ---------------------------------------------------------------------------

#[derive(Debug, Clone, PartialEq)]
pub(crate) struct ParsedToolCall {
    pub(crate) name: String,
    pub(crate) arguments: serde_json::Value,
}

#[derive(Debug, Clone)]
pub(crate) struct ParsedTurn {
    pub(crate) text: String,
    pub(crate) call: Option<ParsedToolCall>,
    pub(crate) corrected: bool,
    pub(crate) rejected_name: Option<String>,
    /// The output looks like a tool-call ATTEMPT (fence + `{` + a name-ish
    /// key) that never produced a parseable object — truncated at the token
    /// cap, unquoted keys, etc. Distinct from prose so the loop can feed back
    /// a correction instead of publishing the wreckage as the final answer.
    pub(crate) malformed: bool,
}

/// Build a `ParsedTurn` from a structured native tool call, bypassing
/// `parse_tool_call`'s fenced-text parsing entirely. Moonshine's contract is
/// one tool per turn, so only the first native call is used; name validation
/// mirrors `parse_tool_call`'s hallucination guard (`rejected_name`).
fn parsed_turn_from_native_tool_calls(
    text: &str,
    native_calls: &[NativeToolCall],
    valid_names: &HashSet<String>,
) -> ParsedTurn {
    let base = ParsedTurn {
        text: text.to_string(),
        call: None,
        corrected: false,
        rejected_name: None,
        malformed: false,
    };
    match native_calls.first() {
        Some(first) if valid_names.contains(&first.name) => ParsedTurn {
            call: Some(ParsedToolCall {
                name: first.name.clone(),
                arguments: first.arguments.clone(),
            }),
            ..base
        },
        Some(first) => ParsedTurn {
            rejected_name: Some(first.name.clone()),
            ..base
        },
        None => base,
    }
}

/// Matches an opening (and, since the tag/newline are optional, also a bare
/// closing) ``` fence. `pub(crate)` so the mesh decode loop in
/// `agent_runtime.rs` can detect a closed tool-call block early — see
/// `tool_call_fence_closed` there.
pub(crate) static FENCE_RE: Lazy<Regex> =
    Lazy::new(|| Regex::new(r"(?i)```[ \t]*(?:tool_call|json)?[ \t]*\r?\n?").unwrap());
static FN_CALL_RE: Lazy<Regex> =
    Lazy::new(|| Regex::new(r"([A-Za-z][A-Za-z0-9_/.\-]*)\s*\(\s*\{").unwrap());

/// Interpret a candidate JSON object as a tool call. Accepts the canonical
/// {"name", "arguments"} shape plus the common small-model deviations:
/// {"tool", "args"} keys and arguments passed as a JSON-encoded string.
fn tool_call_from_json(value: &serde_json::Value) -> Option<(ParsedToolCall, bool)> {
    let object = value.as_object()?;
    let (name, mut corrected) = match object.get("name").and_then(|v| v.as_str()) {
        Some(name) => (name, false),
        None => (object.get("tool").and_then(|v| v.as_str())?, true),
    };
    let name = name.trim();
    if name.is_empty() {
        return None;
    }
    let raw_args = object
        .get("arguments")
        .or_else(|| object.get("args"))
        .cloned()
        .unwrap_or_else(|| serde_json::json!({}));
    let arguments = match raw_args {
        serde_json::Value::Object(_) => raw_args,
        serde_json::Value::String(text) => {
            corrected = true;
            serde_json::from_str::<serde_json::Value>(&text)
                .ok()
                .filter(|v| v.is_object())?
        }
        serde_json::Value::Null => serde_json::json!({}),
        _ => return None,
    };
    Some((
        ParsedToolCall {
            name: name.to_string(),
            arguments,
        },
        corrected,
    ))
}

/// Three-phase forgiving parse (single call per turn). Phase ordering replaces
/// the TS lookbehind guard: later phases only run when earlier ones found
/// nothing.
/// When the loop abandons after repeated malformed tool calls, DON'T publish the
/// raw broken JSON as the answer. Return the prose before the fence, or — if
/// there's no useful prose (the model emitted only a broken tool-call block) — a
/// clean message instead of dumping "```{\"name\":...".
fn failed_tool_answer(text: &str) -> String {
    let prose = text.split("```").next().unwrap_or(text).trim();
    if prose.chars().count() >= 12 {
        prose.to_string()
    } else {
        "I couldn't complete that with a tool call. Try rephrasing — or switch to a general instruct model with `/model` (coding-tuned models are weaker at multi-step tool loops)."
            .to_string()
    }
}

/// Common shell verbs the model reaches for when a query itself contains
/// shell syntax (e.g. "ls -lah AGENTS.md") — there's no tool literally named
/// `ls`, only the namespaced `local/*` equivalents, and previously that
/// instinct just died on contact ("model requested UNAVAILABLE tool 'ls'").
/// Remapped only when the model's own argument shape survives unchanged
/// (all these tools share a `path` argument) and only when the mapped
/// target is actually offered this turn — never invents a tool that wasn't
/// a real candidate.
const SHELL_VERB_ALIASES: &[(&str, &str)] = &[
    ("ls", "local/list_directory"),
    ("dir", "local/list_directory"),
    ("cat", "local/read_file"),
    ("head", "local/read_file"),
    ("tail", "local/read_file"),
    ("less", "local/read_file"),
    ("more", "local/read_file"),
    ("find", "local/search_files"),
    ("grep", "local/search_files"),
    ("rg", "local/search_files"),
];

/// If `name` isn't offered this turn but a well-known shell-verb alias of it
/// IS, use the alias — otherwise leave `name` untouched (the usual
/// unavailable-tool rejection still applies).
fn resolve_shell_verb_alias(name: &str, valid_names: &HashSet<String>) -> String {
    if valid_names.contains(name) {
        return name.to_string();
    }
    SHELL_VERB_ALIASES
        .iter()
        .find(|(verb, _)| *verb == name)
        .map(|(_, target)| *target)
        .filter(|target| valid_names.contains(*target))
        .unwrap_or(name)
        .to_string()
}

pub(crate) fn parse_tool_call(output: &str, valid_names: &HashSet<String>) -> ParsedTurn {
    let text = output.trim().to_string();
    let mut found: Option<(ParsedToolCall, bool)> = None;

    // Phase 1: fenced ```tool_call / ```json block (balanced-brace scan
    // inside the fence body — sturdier than a regex against nested braces).
    for fence in FENCE_RE.find_iter(&text) {
        let body = &text[fence.end()..];
        if let Some(candidate) = extract_json_object(body) {
            if let Ok(value) = serde_json::from_str::<serde_json::Value>(&candidate) {
                if let Some(call) = tool_call_from_json(&value) {
                    found = Some(call);
                    break;
                }
            }
        }
    }

    // Phase 2: a raw JSON object anywhere in the output.
    if found.is_none() {
        if let Some(candidate) = extract_json_object(&text) {
            if let Ok(value) = serde_json::from_str::<serde_json::Value>(&candidate) {
                found = tool_call_from_json(&value);
            }
        }
    }

    // Phase 3: function-call style `tool/name({...})`.
    if found.is_none() {
        if let Some(captures) = FN_CALL_RE.captures(&text) {
            let name = captures.get(1).map(|m| m.as_str().to_string());
            let brace_start = captures.get(0).map(|m| m.end() - 1);
            if let (Some(name), Some(start)) = (name, brace_start) {
                if let Some(candidate) = extract_json_object(&text[start..]) {
                    if let Ok(arguments) =
                        serde_json::from_str::<serde_json::Value>(&candidate)
                    {
                        if arguments.is_object() {
                            found = Some((ParsedToolCall { name, arguments }, true));
                        }
                    }
                }
            }
        }
    }

    match found {
        Some((mut call, mut corrected)) => {
            let aliased = resolve_shell_verb_alias(&call.name, valid_names);
            if aliased != call.name {
                println!(
                    "[agent] model requested shell verb '{}' — remapped to '{}'",
                    call.name, aliased
                );
                call.name = aliased;
                corrected = true;
            }
            if valid_names.contains(&call.name) {
                ParsedTurn {
                    text,
                    call: Some(call),
                    corrected,
                    rejected_name: None,
                    malformed: false,
                }
            } else {
                // Observable: the model DID emit a tool call, just for a tool that
                // wasn't offered this turn (a hallucinated/misremembered name). Log
                // the attempt + args so it's visible, not swallowed into the
                // eventual "I don't recognize that tool" answer.
                println!(
                    "[agent] model requested UNAVAILABLE tool '{}' with args {} — rejecting",
                    call.name, call.arguments
                );
                ParsedTurn {
                    text,
                    call: None,
                    corrected,
                    rejected_name: Some(call.name),
                    malformed: false,
                }
            }
        }
        None => {
            // Tool-call ATTEMPT that produced nothing parseable: a fence whose
            // body opens an object and carries a name-ish key but never closes
            // (truncated at the token cap) or won't parse (unquoted keys).
            // Plain prose — including prose with ordinary code fences — has no
            // `{` + "name"/"tool"/"arguments" combination and stays a final
            // answer.
            let malformed = FENCE_RE
                .find(&text)
                .map(|fence| &text[fence.end()..])
                .map(|body| {
                    body.contains('{')
                        && (body.contains("\"name\"")
                            || body.contains("\"tool\"")
                            || body.contains("\"arguments\""))
                })
                .unwrap_or(false);
            if malformed {
                println!(
                    "[agent] model emitted a malformed/truncated tool call — asking it to retry"
                );
            }
            ParsedTurn {
                text,
                call: None,
                corrected: false,
                rejected_name: None,
                malformed,
            }
        }
    }
}

// ---------------------------------------------------------------------------
// Event plumbing
// ---------------------------------------------------------------------------

fn base_event(kind: &'static str, cfg: &AgentLoopConfig) -> AgentJsonEvent {
    let mut event = AgentJsonEvent::new(kind);
    event.run_id = Some(cfg.run_id.clone());
    event.workspace_path = Some(cfg.workspace.to_string_lossy().into_owned());
    event.permission_mode = Some(cfg.permission_mode.as_str().to_string());
    event.provider = Some(cfg.provider.clone());
    event
}

/// json mode: NDJSON to stdout + ledger. Human mode: ledger only, so the REPL
/// transcript stays readable while `agentic runs`/`replay` still see the run.
fn emit_event(event: AgentJsonEvent, cfg: &AgentLoopConfig) -> Result<()> {
    if cfg.json_events {
        super::emit_agent_json_event(event, cfg.ledger_path.as_deref())
    } else {
        append_ledger_only(event, cfg.ledger_path.as_deref())
    }
}

pub(crate) fn append_ledger_only(event: AgentJsonEvent, ledger_path: Option<&Path>) -> Result<()> {
    let Some(path) = ledger_path else {
        return Ok(());
    };
    let mut line = serde_json::to_string(&event)?;
    line.push('\n');
    if let Some(parent) = path.parent() {
        std::fs::create_dir_all(parent)?;
    }
    std::fs::OpenOptions::new()
        .create(true)
        .append(true)
        .open(path)?
        .write_all(line.as_bytes())?;
    Ok(())
}

fn tool_intent(
    cfg: &AgentLoopConfig,
    intent_id: &str,
    tool_name: &str,
    profile: &ToolRiskProfile,
    status: &str,
) -> ToolIntentRecord {
    ToolIntentRecord {
        schema_version: AGENT_EXEC_SCHEMA_VERSION,
        run_id: cfg.run_id.clone(),
        intent_id: intent_id.to_string(),
        workspace_path: cfg.workspace.to_string_lossy().into_owned(),
        permission_mode: cfg.permission_mode.as_str().to_string(),
        provider: cfg.provider.clone(),
        tool_name: tool_name.to_string(),
        requested_action: profile.requested_action.clone(),
        risk: profile.risk.to_string(),
        formal_target: None,
        verification_command: None,
        status: status.to_string(),
        created_at: chrono::Utc::now().to_rfc3339(),
    }
}

fn prompt_yes_no(question: &str) -> bool {
    print!("{question} [y/N] ");
    let _ = std::io::stdout().flush();
    let mut line = String::new();
    if std::io::stdin().read_line(&mut line).is_err() {
        return false;
    }
    matches!(line.trim().to_lowercase().as_str(), "y" | "yes")
}

// ---------------------------------------------------------------------------
// The loop
// ---------------------------------------------------------------------------

const PLAIN_SYSTEM_PROMPT: &str =
    "You are Moonshine, a terminal agent. Answer the user directly and concisely.";

fn transcript_messages(
    system: String,
    history: &[(String, String)],
    input: &str,
) -> Vec<ChatMessage> {
    let mut messages = vec![ChatMessage::system(system)];
    for (user, assistant) in history {
        messages.push(ChatMessage::user(user.clone()));
        messages.push(ChatMessage::assistant(assistant.clone()));
    }
    messages.push(ChatMessage::user(input.to_string()));
    messages
}

async fn plain_answer(
    input: &str,
    history: &[(String, String)],
    brain: &Brain,
) -> Result<LoopOutcome> {
    let messages = transcript_messages(PLAIN_SYSTEM_PROMPT.to_string(), history, input);
    let completion = brain.complete(&messages, None).await?;
    Ok(LoopOutcome::Answer(completion.text))
}

pub(crate) async fn run_agent_turn(
    input: &str,
    history: &[(String, String)],
    catalog: Option<&AgentToolIndex>,
    brain: &Brain,
    cfg: &AgentLoopConfig,
) -> Result<(LoopOutcome, EconomySummary)> {
    let mut economy = AgentEconomy::new(cfg.max_stamina);
    let Some(catalog) = catalog.filter(|c| !c.tools.is_empty()) else {
        return plain_answer(input, history, brain)
            .await
            .map(|outcome| (outcome, economy.summary()));
    };
    let mut session = match McpSession::connect().await {
        Ok(session) => session,
        Err(error) => {
            eprintln!("[agent] MCP session unavailable ({error}); answering without tools");
            return plain_answer(input, history, brain)
                .await
                .map(|outcome| (outcome, economy.summary()));
        }
    };

    let caps = prompt_caps(brain.kind());
    let limit = candidate_limit().min(caps.max_candidates);
    let candidates = select_candidate_tools(catalog, &mut session, input, limit).await;
    if candidates.is_empty() {
        return plain_answer(input, history, brain)
            .await
            .map(|outcome| (outcome, economy.summary()));
    }
    if !cfg.json_events {
        let names: Vec<&str> = candidates.iter().map(|t| t.name.as_str()).collect();
        println!("[agent] tools on offer: {}", names.join(", "));
    }

    let candidate_risk: HashMap<String, &'static str> = candidates
        .iter()
        .map(|t| (t.name.clone(), classify_tool_risk(t, &serde_json::json!({})).risk))
        .collect();
    let all_names: HashSet<String> = catalog.tools.iter().map(|t| t.name.clone()).collect();
    let economy_active = agent_economy::economy_enabled();
    let mut messages = transcript_messages(String::new(), history, input);

    let mut format_strikes = 0usize;
    let mut tool_calls_used = 0usize;
    let mut tool_error_counts: HashMap<String, usize> = HashMap::new();
    // Degen guard for tools (the mirror of the decoder's `detect_repeat_cycle`):
    // the signature `name|args` of every EXECUTED call → the feedback to give if
    // the model re-issues it. Re-issuing a call is degenerate whether it FAILED
    // (doomed — re-fails and drains the budget) or SUCCEEDED (the result is already
    // in context — the model should ANSWER, not re-list the same directory forever;
    // the loop weak models fall into). They ignore polite "use the result" feedback,
    // so we HARD-BLOCK the repeat and bail to a final answer after two.
    let mut executed_call_signatures: HashMap<String, String> = HashMap::new();
    let mut repeated_calls = 0usize;
    let mut intent_seq = 0usize;

    for turn in 1..=cfg.max_turns {
        let turn_candidates = if economy_active {
            narrow_if_winded(&candidates, &candidate_risk, economy.winded)
        } else {
            candidates.clone()
        };
        let candidate_names: HashSet<String> =
            turn_candidates.iter().map(|t| t.name.clone()).collect();
        let system_prompt = build_system_prompt(&turn_candidates, &caps);
        messages[0] = ChatMessage::system(if economy_active && !economy.is_at_rest() {
            format!("{}\n{}", system_prompt, agent_economy::economy_status_block(&economy))
        } else {
            system_prompt
        });
        if !cfg.json_events {
            println!("[agent] turn {}/{}: thinking…", turn, cfg.max_turns);
        }
        let native_tools = build_native_tools_json(&turn_candidates);
        let mut completion = brain.complete(&messages, Some(&native_tools)).await?;
        let mut parsed = match &completion.tool_calls {
            Some(native_calls) => {
                parsed_turn_from_native_tool_calls(&completion.text, native_calls, &candidate_names)
            }
            None => parse_tool_call(&completion.text, &candidate_names),
        };

        // --- Skymesh plain-prose retry: one extra opinion, never a loop ----
        let is_plain_prose =
            parsed.call.is_none() && parsed.rejected_name.is_none() && !parsed.malformed;
        if should_retry_via_fat_station(
            turn,
            completion.backend,
            is_plain_prose,
            has_strong_local_cue(input, &catalog.tools, &turn_candidates),
        ) {
            if !cfg.json_events {
                println!(
                    "[agent] skymesh answered in prose despite a strong local match; asking fat-station for a second opinion"
                );
            }
            match brain.with_kind(BrainKind::FatStation).complete(&messages, None).await {
                Ok(retry_completion) => {
                    let retry_parsed = parse_tool_call(&retry_completion.text, &candidate_names);
                    if retry_parsed.call.is_some() {
                        completion = retry_completion;
                        parsed = retry_parsed;
                    } else if !cfg.json_events {
                        println!("[agent] fat-station also answered in prose; keeping skymesh's answer");
                    }
                }
                Err(error) => {
                    if !cfg.json_events {
                        eprintln!(
                            "[agent] fat-station second opinion unavailable ({error}); keeping skymesh's answer"
                        );
                    }
                }
            }
        }

        if !cfg.json_events && turn == 1 {
            // brain.model() only carries the skymesh leg's model id — for
            // fat-station it's meaningless (that field is unused by that
            // backend), so resolve the actual running knot separately.
            let model_display = if completion.backend == "fat-station" {
                super::fat_station_model_display()
            } else {
                brain.model().to_string()
            };
            println!("[agent] brain: {} (model={})", completion.backend, model_display);
        }
        if parsed.corrected && !cfg.json_events {
            println!("[agent] tool-call format recovered by the forgiving parser");
        }

        let Some(call) = parsed.call else {
            if let Some(rejected) = parsed.rejected_name {
                format_strikes += 1;
                if format_strikes >= 2 {
                    return Ok((
                        LoopOutcome::Answer(failed_tool_answer(&parsed.text)),
                        economy.summary(),
                    ));
                }
                let feedback = if all_names.contains(&rejected) {
                    format!(
                        "TOOL ERROR: tool '{rejected}' was not offered. Pick one of the AVAILABLE TOOLS, or answer directly."
                    )
                } else {
                    format!(
                        "TOOL ERROR: no tool named '{rejected}' exists. Pick one of the AVAILABLE TOOLS, or answer directly."
                    )
                };
                messages.push(ChatMessage::assistant(parsed.text));
                messages.push(ChatMessage::user(feedback));
                continue;
            }
            if parsed.malformed {
                format_strikes += 1;
                if format_strikes >= 2 {
                    return Ok((
                        LoopOutcome::Answer(failed_tool_answer(&parsed.text)),
                        economy.summary(),
                    ));
                }
                messages.push(ChatMessage::assistant(parsed.text));
                messages.push(ChatMessage::user(
                    "TOOL ERROR: your tool call was malformed or truncated. Output exactly ONE complete ```tool_call block of valid JSON ({\"name\": ..., \"arguments\": {...}}), keep it short, or answer in plain text."
                        .to_string(),
                ));
                continue;
            }
            // Plain text — the final answer.
            if economy_active {
                economy.award_finisher_if_citing(&parsed.text);
            }
            return Ok((LoopOutcome::Answer(parsed.text), economy.summary()));
        };
        format_strikes = 0;

        let Some(tool) = catalog.tools.iter().find(|t| t.name == call.name) else {
            // Unreachable (candidate names come from the catalog), but stay safe.
            return Ok((LoopOutcome::Answer(parsed.text), economy.summary()));
        };

        let validation_errors = validate_tool_args(&tool.meta.input_schema, &call.arguments);
        if !validation_errors.is_empty() {
            format_strikes += 1;
            if format_strikes >= 2 {
                return Ok((
                    LoopOutcome::Answer(failed_tool_answer(&parsed.text)),
                    economy.summary(),
                ));
            }
            let feedback = format!(
                "TOOL ERROR for {}: {}. Fix the arguments and try again, or answer without the tool.",
                call.name,
                validation_errors.join("; ")
            );
            messages.push(ChatMessage::assistant(parsed.text));
            messages.push(ChatMessage::user(feedback));
            continue;
        }

        if tool_calls_used >= cfg.max_tool_calls {
            break;
        }

        // --- Metacog gate at the execution choke point --------------------
        intent_seq += 1;
        let intent_id = format!("{}-tool-{}", cfg.run_id, intent_seq);
        let profile = classify_tool_risk(tool, &call.arguments);
        let gate = decide_metacog_for_tool(&profile, &cfg.permission_mode);

        let mut verdict_event = base_event("metacog_verdict", cfg);
        verdict_event.intent_id = Some(intent_id.clone());
        verdict_event.tool_name = Some(call.name.clone());
        verdict_event.verdict = Some(gate.verdict.to_string());
        verdict_event.reason = Some(gate.reason.clone());
        verdict_event.requested_action = Some(profile.requested_action.clone());
        verdict_event.risk = Some(profile.risk.to_string());
        verdict_event.content = Some(format!(
            "risk source {}, authority {}",
            profile.source, tool.meta.authority_kind
        ));
        emit_event(verdict_event, cfg)?;

        let mut denied_reason: Option<String> = None;
        match gate.verdict {
            "veto" => {
                let record = tool_intent(cfg, &intent_id, &call.name, &profile, "denied");
                super::persist_tool_intent(&cfg.workspace, &record)?;
                emit_event(tool_event_from_record("tool_denial", &record), cfg)?;
                denied_reason = Some(gate.reason.clone());
            }
            "escalate" => {
                if cfg.interactive {
                    let question = format!(
                        "Tool {} {} — risk {}. Approve?",
                        call.name, call.arguments, profile.risk
                    );
                    if prompt_yes_no(&question) {
                        let record =
                            tool_intent(cfg, &intent_id, &call.name, &profile, "approved");
                        super::persist_tool_intent(&cfg.workspace, &record)?;
                        emit_event(tool_event_from_record("tool_admission", &record), cfg)?;
                    } else {
                        let record =
                            tool_intent(cfg, &intent_id, &call.name, &profile, "denied");
                        super::persist_tool_intent(&cfg.workspace, &record)?;
                        emit_event(tool_event_from_record("tool_denial", &record), cfg)?;
                        denied_reason = Some("denied by operator".to_string());
                    }
                } else {
                    let record = tool_intent(cfg, &intent_id, &call.name, &profile, "pending");
                    super::persist_tool_intent(&cfg.workspace, &record)?;
                    emit_event(tool_event_from_record("tool_admission", &record), cfg)?;

                    let mut permission = base_event("permission_request", cfg);
                    permission.intent_id = Some(intent_id.clone());
                    permission.tool_name = Some(call.name.clone());
                    permission.verdict = Some(gate.verdict.to_string());
                    permission.reason = Some(gate.reason.clone());
                    permission.requested_action = Some(profile.requested_action.clone());
                    permission.risk = Some(profile.risk.to_string());
                    permission.status = Some("pending".to_string());
                    permission.choices =
                        Some(vec!["approve_once".to_string(), "deny".to_string()]);
                    permission.content = Some(format!("arguments: {}", call.arguments));
                    emit_event(permission, cfg)?;

                    let mut checkpoint = base_event("run_checkpoint", cfg);
                    checkpoint.intent_id = Some(intent_id.clone());
                    checkpoint.tool_name = Some(call.name.clone());
                    checkpoint.content =
                        Some("tool intent awaiting human admission".to_string());
                    emit_event(checkpoint, cfg)?;
                    return Ok((LoopOutcome::NeedsApproval { intent_id }, economy.summary()));
                }
            }
            _ => {}
        }

        if let Some(reason) = denied_reason {
            let feedback = format!(
                "TOOL DENIED: {} was blocked by policy ({}). Answer the user without this tool.",
                call.name, reason
            );
            messages.push(ChatMessage::assistant(parsed.text));
            messages.push(ChatMessage::user(feedback));
            continue;
        }

        // --- Degen guard: block a re-issued identical call ------------------
        // Mirrors the decoder's cycle detection. Re-emitting the exact same
        // (name, args) is degenerate whether the prior call FAILED (re-fails) or
        // SUCCEEDED (the result is already above — the model should answer, not
        // re-run the same listing). Hard-block it; after two repeats stop tool use
        // entirely and force a final answer.
        let call_signature = format!("{}|{}", call.name, call.arguments);
        if let Some(prev_outcome) = executed_call_signatures.get(&call_signature).cloned() {
            repeated_calls += 1;
            if !cfg.json_events {
                println!(
                    "[agent] BLOCKED repeated call {} (identical args already executed) — degen loop guard",
                    call.name
                );
            }
            if repeated_calls >= 2 {
                messages.push(ChatMessage::user(format!(
                    "You keep re-issuing the same {} call. {} Stop calling tools and ANSWER the user now with what you already have.",
                    call.name, prev_outcome
                )));
                break;
            }
            let feedback = format!(
                "BLOCKED: you already called {} with these EXACT arguments. {} Do NOT repeat it — ANSWER the user with the result you already have, or call a DIFFERENT tool.",
                call.name, prev_outcome
            );
            messages.push(ChatMessage::assistant(parsed.text));
            messages.push(ChatMessage::user(feedback));
            continue;
        }

        // --- Execute --------------------------------------------------------
        if !cfg.json_events {
            println!("[agent] calling {} {}", call.name, call.arguments);
        }
        let mut request = base_event("tool_request", cfg);
        request.intent_id = Some(intent_id.clone());
        request.tool_name = Some(call.name.clone());
        request.command = Some(call.arguments.to_string());
        request.requested_action = Some(profile.requested_action.clone());
        request.risk = Some(profile.risk.to_string());
        request.status = Some("executed".to_string());
        emit_event(request, cfg)?;

        let started = Instant::now();
        let outcome = session
            .call_tool(&call.name, call.arguments.clone(), tool_call_timeout())
            .await;
        let duration_ms = started.elapsed().as_millis();
        tool_calls_used += 1;

        let mut result_event = base_event("tool_result", cfg);
        result_event.intent_id = Some(intent_id.clone());
        result_event.tool_name = Some(call.name.clone());
        result_event.duration_ms = Some(duration_ms);
        result_event.requested_action = Some(profile.requested_action.clone());
        result_event.risk = Some(profile.risk.to_string());

        match outcome {
            Ok(result) => {
                let result_text = tool_result_text(&result, caps.result_chars);
                result_event.status = Some("passed".to_string());
                result_event.content = Some(result_text.clone());
                emit_event(result_event, cfg)?;
                if economy_active {
                    economy.record_success(tool, profile.risk, &call.arguments, &result_text);
                }
                // Remember this exact (name, args) so an identical re-issue is
                // hard-blocked by the degen guard. The directive is concrete — weak
                // models re-run the call because "answer the user" is too vague, so
                // tell them exactly what to do with the result they already have:
                // DESCRIBE it (count / list / summarize).
                executed_call_signatures.insert(
                    call_signature.clone(),
                    format!(
                        "It already returned a result ({} chars), shown above — now use it to answer the user's ORIGINAL question: count, list, or summarize what it contains, exactly as that question asks.",
                        result_text.chars().count()
                    ),
                );
                if !cfg.json_events {
                    println!(
                        "[agent] {} -> {} char(s) in {}ms",
                        call.name,
                        result_text.chars().count(),
                        duration_ms
                    );
                }
                let feedback = format!(
                    "TOOL RESULT for {}:\n{}\nUse this result. Answer the user, or call another tool if needed.",
                    call.name, result_text
                );
                messages.push(ChatMessage::assistant(parsed.text));
                messages.push(ChatMessage::user(feedback));
            }
            Err(error) => {
                result_event.status = Some("failed".to_string());
                result_event.error = Some(error.to_string());
                emit_event(result_event, cfg)?;
                if economy_active {
                    economy.record_failure(profile.risk);
                }
                // Remember this exact (name, args) so an identical re-issue is
                // hard-blocked by the degen guard above instead of re-executed.
                executed_call_signatures.insert(
                    call_signature.clone(),
                    format!("It already failed: {}.", error),
                );
                let failures = tool_error_counts.entry(call.name.clone()).or_insert(0);
                *failures += 1;
                let feedback = if *failures >= 2 {
                    format!(
                        "TOOL ERROR for {}: {}. This tool has failed repeatedly — do not call it again. Answer without it.",
                        call.name, error
                    )
                } else {
                    format!(
                        "TOOL ERROR for {}: {}. Fix the arguments and try again, or answer without the tool.",
                        call.name, error
                    )
                };
                messages.push(ChatMessage::assistant(parsed.text));
                messages.push(ChatMessage::user(feedback));
            }
        }
    }

    // Budget exhausted: one final no-tools call.
    messages.push(ChatMessage::user(
        "Answer the user now with what you have. Do not call any tools.".to_string(),
    ));
    let completion = brain.complete(&messages, None).await?;
    let parsed = parse_tool_call(&completion.text, &HashSet::new());
    let text = if parsed.call.is_some() || parsed.rejected_name.is_some() {
        "(tool budget exhausted before a final answer)".to_string()
    } else {
        if economy_active {
            economy.award_finisher_if_citing(&parsed.text);
        }
        parsed.text
    };
    Ok((LoopOutcome::BudgetExhausted(text), economy.summary()))
}

#[cfg(test)]
mod agent_loop_tests {
    use super::super::agent_tools::ToolMeta;
    use super::*;

    fn names(items: &[&str]) -> HashSet<String> {
        items.iter().map(|s| s.to_string()).collect()
    }

    #[test]
    fn parses_fenced_tool_call_block() {
        let output = "I'll search.\n```tool_call\n{\"name\": \"network/search\", \"arguments\": {\"query\": \"a.b\"}}\n```";
        let parsed = parse_tool_call(output, &names(&["network/search"]));
        let call = parsed.call.expect("call");
        assert_eq!(call.name, "network/search");
        assert_eq!(call.arguments["query"], "a.b");
        assert!(!parsed.corrected);
    }

    #[test]
    fn parses_fence_after_think_block_and_nested_braces() {
        let raw = "<think>maybe tool</think>\n```json\n{\"name\": \"local/fs_read\", \"arguments\": {\"opts\": {\"path\": \"a}b.txt\"}}}\n```";
        let cleaned = super::super::strip_think_block(raw);
        let parsed = parse_tool_call(&cleaned, &names(&["local/fs_read"]));
        let call = parsed.call.expect("call");
        assert_eq!(call.arguments["opts"]["path"], "a}b.txt");
    }

    #[test]
    fn parses_raw_json_and_corrected_variants() {
        let parsed = parse_tool_call(
            "{\"tool\": \"network/search\", \"args\": {\"query\": \"x\"}}",
            &names(&["network/search"]),
        );
        assert!(parsed.corrected);
        assert_eq!(parsed.call.expect("call").name, "network/search");

        // Arguments as a JSON-encoded string.
        let parsed = parse_tool_call(
            "{\"name\": \"network/search\", \"arguments\": \"{\\\"query\\\": \\\"x\\\"}\"}",
            &names(&["network/search"]),
        );
        assert!(parsed.corrected);
        assert_eq!(parsed.call.expect("call").arguments["query"], "x");
    }

    #[test]
    fn parses_function_call_style() {
        let parsed = parse_tool_call(
            "Let me run network/search({\"query\": \"weather\"}) now.",
            &names(&["network/search"]),
        );
        assert!(parsed.corrected);
        assert_eq!(parsed.call.expect("call").name, "network/search");
    }

    #[test]
    fn rejects_hallucinated_tool_names() {
        let parsed = parse_tool_call(
            "```tool_call\n{\"name\": \"made_up/tool\", \"arguments\": {}}\n```",
            &names(&["network/search"]),
        );
        assert!(parsed.call.is_none());
        assert_eq!(parsed.rejected_name.as_deref(), Some("made_up/tool"));
    }

    #[test]
    fn remaps_shell_verb_to_its_local_tool_equivalent_when_offered() {
        // The model reaches for `ls` when the user's own query contains
        // shell syntax ("ls -lah AGENTS.md") — previously a flat rejection
        // even though the semantically equivalent tool was right there.
        let parsed = parse_tool_call(
            "```tool_call\n{\"name\": \"ls\", \"arguments\": {\"path\": \"AGENTS.md\"}}\n```",
            &names(&["local/list_directory", "network/search"]),
        );
        let call = parsed.call.expect("call");
        assert_eq!(call.name, "local/list_directory");
        assert_eq!(call.arguments["path"], "AGENTS.md");
        assert!(parsed.corrected);
    }

    #[test]
    fn shell_verb_alias_does_not_fire_when_the_target_is_not_offered() {
        // No local/* tools on offer this turn — `ls` stays a genuine
        // unavailable-tool rejection rather than inventing a candidate.
        let parsed = parse_tool_call(
            "```tool_call\n{\"name\": \"ls\", \"arguments\": {\"path\": \"AGENTS.md\"}}\n```",
            &names(&["network/search"]),
        );
        assert!(parsed.call.is_none());
        assert_eq!(parsed.rejected_name.as_deref(), Some("ls"));
    }

    #[test]
    fn shell_verb_alias_is_a_noop_when_the_literal_name_is_already_offered() {
        // If a real tool is ever actually named "ls", prefer it verbatim
        // over remapping.
        let parsed = parse_tool_call(
            "```tool_call\n{\"name\": \"ls\", \"arguments\": {}}\n```",
            &names(&["ls"]),
        );
        assert_eq!(parsed.call.expect("call").name, "ls");
        assert!(!parsed.corrected);
    }

    #[test]
    fn native_tool_call_with_valid_name_becomes_a_call() {
        let native_calls = vec![NativeToolCall {
            name: "network/search".to_string(),
            arguments: serde_json::json!({"query": "a.b"}),
        }];
        let parsed =
            parsed_turn_from_native_tool_calls("", &native_calls, &names(&["network/search"]));
        let call = parsed.call.expect("call");
        assert_eq!(call.name, "network/search");
        assert_eq!(call.arguments["query"], "a.b");
        assert!(parsed.rejected_name.is_none());
        assert!(!parsed.malformed);
    }

    #[test]
    fn native_tool_call_with_hallucinated_name_is_rejected() {
        let native_calls = vec![NativeToolCall {
            name: "made_up/tool".to_string(),
            arguments: serde_json::json!({}),
        }];
        let parsed =
            parsed_turn_from_native_tool_calls("", &native_calls, &names(&["network/search"]));
        assert!(parsed.call.is_none());
        assert_eq!(parsed.rejected_name.as_deref(), Some("made_up/tool"));
    }

    #[test]
    fn native_tool_call_only_uses_the_first_of_multiple_calls() {
        // Moonshine's contract is one tool per turn even if a native
        // endpoint proposes several.
        let native_calls = vec![
            NativeToolCall {
                name: "network/search".to_string(),
                arguments: serde_json::json!({"query": "first"}),
            },
            NativeToolCall {
                name: "local/read_file".to_string(),
                arguments: serde_json::json!({"path": "second"}),
            },
        ];
        let parsed = parsed_turn_from_native_tool_calls(
            "",
            &native_calls,
            &names(&["network/search", "local/read_file"]),
        );
        assert_eq!(parsed.call.expect("call").name, "network/search");
    }

    #[test]
    fn empty_native_tool_calls_yields_plain_text_turn() {
        let parsed = parsed_turn_from_native_tool_calls("just an answer", &[], &names(&[]));
        assert!(parsed.call.is_none());
        assert!(parsed.rejected_name.is_none());
        assert!(!parsed.malformed);
        assert_eq!(parsed.text, "just an answer");
    }

    #[test]
    fn native_tools_json_mirrors_candidate_names_and_schemas() {
        let tool = AgentIndexedTool {
            name: "network/search".to_string(),
            description: "Search the network".to_string(),
            raw: serde_json::json!({}),
            name_lower: "network/search".to_string(),
            description_lower: "search the network".to_string(),
            raw_lower: String::new(),
            meta: ToolMeta {
                input_schema: serde_json::json!({
                    "type": "object",
                    "properties": {"query": {"type": "string"}},
                    "required": ["query"],
                }),
                ..ToolMeta::default()
            },
        };
        let candidates = vec![&tool];
        let json = build_native_tools_json(&candidates);
        let entry = &json[0];
        assert_eq!(entry["type"], "function");
        assert_eq!(entry["function"]["name"], "network/search");
        assert_eq!(entry["function"]["description"], "Search the network");
        assert_eq!(entry["function"]["parameters"]["required"][0], "query");
    }

    #[test]
    fn truncated_tool_call_attempt_is_malformed_not_final() {
        // The 2026-07-05 rwkv7-mini failure shape: fenced call attempt with
        // unquoted keys, degenerating repetition, cut at the token cap — the
        // object never closes.
        let output = "```\n{\n  \"name\": \"weather_lookup\",\n  \"arguments\": {\n    query: \"weather\",\n    query_type: \"weather\",\n    query_name";
        let parsed = parse_tool_call(output, &names(&["network/search"]));
        assert!(parsed.call.is_none());
        assert!(parsed.rejected_name.is_none());
        assert!(parsed.malformed);
        // Prose with an ordinary code fence (no call shape) stays a final answer.
        let prose = parse_tool_call(
            "To search for weather tools, we can use the following command:\n```\ncurl example\n```",
            &names(&["network/search"]),
        );
        assert!(!prose.malformed);
    }

    #[test]
    fn plain_text_is_a_final_answer() {
        let parsed = parse_tool_call(
            "The capital of France is Paris.",
            &names(&["network/search"]),
        );
        assert!(parsed.call.is_none());
        assert!(parsed.rejected_name.is_none());
        assert_eq!(parsed.text, "The capital of France is Paris.");
    }

    #[test]
    fn quoted_json_without_call_shape_is_not_a_call() {
        let parsed = parse_tool_call(
            "The config is {\"retries\": 3, \"mode\": \"fast\"} as documented.",
            &names(&["network/search"]),
        );
        assert!(parsed.call.is_none());
        assert!(parsed.rejected_name.is_none());
    }

    #[test]
    fn system_prompt_lists_tools_with_required_markers() {
        let tool = AgentIndexedTool {
            name: "local/fs_read".to_string(),
            description: "Read a file from the workspace.".to_string(),
            raw: serde_json::json!({}),
            name_lower: "local/fs_read".to_string(),
            description_lower: String::new(),
            raw_lower: String::new(),
            meta: ToolMeta {
                input_schema: serde_json::json!({
                    "type": "object",
                    "properties": {
                        "path": {"type": "string", "description": "workspace-relative path"},
                        "limit": {"type": "integer"}
                    },
                    "required": ["path"]
                }),
                ..ToolMeta::default()
            },
        };
        let caps = PromptCaps {
            max_candidates: 6,
            desc_chars: 200,
            result_chars: 2000,
        };
        let prompt = build_system_prompt(&[&tool], &caps);
        assert!(prompt.contains("### local/fs_read"));
        assert!(prompt.contains("- path: workspace-relative path (required)"));
        assert!(prompt.contains("- limit: integer\n"));
        assert!(prompt.contains("```tool_call"));
    }

    #[test]
    fn tool_result_text_prefers_content_text_and_truncates() {
        let result = serde_json::json!({
            "content": [{"type": "text", "text": "hello world"}]
        });
        assert_eq!(tool_result_text(&result, 100), "hello world");
        let truncated = tool_result_text(&result, 5);
        assert!(truncated.starts_with("hello"));
        assert!(truncated.contains("truncated"));
        let bare = serde_json::json!({"ok": true});
        assert_eq!(tool_result_text(&bare, 100), "{\"ok\":true}");
    }

    #[test]
    fn winded_state_narrows_turn_candidates_to_read_only_only() {
        let read = AgentIndexedTool {
            name: "local/read_file".to_string(),
            description: String::new(),
            raw: serde_json::json!({}),
            name_lower: "local/read_file".to_string(),
            description_lower: String::new(),
            raw_lower: String::new(),
            meta: ToolMeta::default(),
        };
        let write = AgentIndexedTool {
            name: "local/write_file".to_string(),
            description: String::new(),
            raw: serde_json::json!({}),
            name_lower: "local/write_file".to_string(),
            description_lower: String::new(),
            raw_lower: String::new(),
            meta: ToolMeta::default(),
        };
        let candidates = vec![&read, &write];
        let mut risk: HashMap<String, &'static str> = HashMap::new();
        risk.insert(read.name.clone(), "read_only");
        risk.insert(write.name.clone(), "workspace_write");

        let not_winded = narrow_if_winded(&candidates, &risk, false);
        assert_eq!(not_winded.len(), 2);

        let winded = narrow_if_winded(&candidates, &risk, true);
        assert_eq!(winded.len(), 1);
        assert_eq!(winded[0].name, "local/read_file");
    }

    fn cue_tool(name: &str, description: &str) -> AgentIndexedTool {
        AgentIndexedTool {
            name: name.to_string(),
            description: description.to_string(),
            raw: serde_json::json!({}),
            name_lower: name.to_lowercase(),
            description_lower: description.to_lowercase(),
            raw_lower: format!("{} {}", name, description).to_lowercase(),
            meta: ToolMeta::default(),
        }
    }

    /// A handful of unrelated filler tools, so document-frequency rarity
    /// weighting sees a realistic catalog shape rather than a degenerate
    /// single/double-tool one (where every token would misread as maximally
    /// rare).
    fn filler_tools() -> Vec<AgentIndexedTool> {
        vec![
            cue_tool("aic/delegation_verify", "verify a UCAN delegation chain"),
            cue_tool("coherence/verify_traced_axioms", "verify traced monoidal axioms"),
            cue_tool("forgo-trd/forgo_trd_verify_topology", "verify GG topology checks"),
            cue_tool("network/search", "search the tool registry"),
        ]
    }

    #[test]
    fn has_strong_local_cue_crosses_threshold_for_a_real_strong_match() {
        // Mirrors the real production `local/list_directory` metadata (as
        // populated by `ToolMeta::from_raw` from the superserver's
        // `x-forkjoin` block).
        let mut tool = cue_tool(
            "local/list_directory",
            "list files and directories under the current monorepo root",
        );
        tool.meta.namespace = "local".to_string();
        tool.meta.domains = vec!["filesystem".to_string()];
        let mut full_catalog = filler_tools();
        full_catalog.push(tool.clone());
        assert!(has_strong_local_cue(
            "how many files in this directory",
            &full_catalog,
            &[&tool]
        ));
    }

    #[test]
    fn has_strong_local_cue_stays_false_for_a_weak_single_hit() {
        // Only a raw-substring hit, nowhere near the strong-cue bar.
        let tool = cue_tool("network/search", "search the tool registry");
        let mut full_catalog = filler_tools();
        full_catalog.push(tool.clone());
        assert!(!has_strong_local_cue(
            "how many files in this directory",
            &full_catalog,
            &[&tool]
        ));
    }

    #[test]
    fn should_retry_via_fat_station_fires_only_on_the_exact_combination() {
        assert!(should_retry_via_fat_station(1, "skymesh", true, true));
        assert!(!should_retry_via_fat_station(2, "skymesh", true, true));
        assert!(!should_retry_via_fat_station(1, "fat-station", true, true));
        assert!(!should_retry_via_fat_station(1, "skymesh", false, true));
        assert!(!should_retry_via_fat_station(1, "skymesh", true, false));
    }
}
